#include <stdio.h>
#include <stdlib.h>
#include <string.h>

const char *keypad[] = {"", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"};

void backtrack(const char *digits, int pos, char *cur, char ***out, int *cnt, int *cap) {
    if (digits[pos] == '\0') {
        if (*cnt >= *cap) {
            *cap = (*cap == 0) ? 1 : (*cap * 2);
            *out = realloc(*out, (*cap) * sizeof(char*));
        }
        (*out)[(*cnt)++] = strdup(cur);
        return;
    }
    const char *letters = keypad[digits[pos] - '0'];
    for (int i = 0; letters[i]; ++i) {
        cur[pos] = letters[i];
        cur[pos+1] = '\0';
        backtrack(digits, pos+1, cur, out, cnt, cap);
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char digits[10];
        scanf("%s", digits);
        char **result = NULL;
        int cnt = 0, cap = 0;
        char cur[10] = "";
        backtrack(digits, 0, cur, &result, &cnt, &cap);
        for (int i = 0; i < cnt; ++i) {
            printf("%s", result[i]);
            if (i + 1 < cnt) printf(" ");
            free(result[i]);
        }
        printf("\n");
        free(result);
    }
    return 0;
}

