            if(idx==(int)digits.size()){
                res.push_back(cur);
                return;
            }
            const string &letters = keypad[digits[idx]-'0'];
            for(char c: letters){
                cur.push_back(c);
                dfs(idx+1);
                cur.pop_back();
            }
        };
        dfs(0);
        for(size_t i=0;i<res.size();++i){
            if(i) cout<<' ';
            cout<<res[i];
        }
        cout<<'\n';
    }
    return 0;
}

