import java.io.*;
import java.util.*;
public class Main {
    private static final String[] KEYPAD = {"", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"};
    private static void backtrack(String digits, int idx, StringBuilder cur, List<String> out){
        if(idx==digits.length()){
            out.add(cur.toString());
            return;
        }
        String letters = KEYPAD[digits.charAt(idx)-'0'];
        for(char ch: letters.toCharArray()){
            cur.append(ch);
            backtrack(digits, idx+1, cur, out);
            cur.deleteCharAt(cur.length()-1);
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for(int t=0;t<T;++t){
            String digits = br.readLine().trim();
            List<String> res = new ArrayList<>();
            if(!digits.isEmpty() && digits.charAt(0) >= '2' && digits.charAt(0) <= '9') backtrack(digits,0,new StringBuilder(),res);
            for(int i=0;i<res.size();++i){
                if(i>0) sb.append(' ');
                sb.append(res.get(i));
            }
            sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys
keypad = {
    '2': 'abc', '3': 'def', '4': 'ghi', '5': 'jkl',
    '6': 'mno', '7': 'pqrs', '8': 'tuv', '9': 'wxyz'
}

def backtrack(digits, idx, cur, out):
    if idx == len(digits):
        out.append(''.join(cur))
        return
    for ch in keypad[digits[idx]]:
        cur.append(ch)
        backtrack(digits, idx+1, cur, out)
        cur.pop()

def solve():
    data = sys.stdin.read().splitlines()
    if not data: return
    T = int(data[0])
    out_lines = []
    for i in range(1, T+1):
        digits = data[i].strip()
        res = []
        if digits and '0' not in digits and '1' not in digits:
            backtrack(digits, 0, [], res)
        out_lines.append(' '.join(res))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

